solutionFiles.content:
def trim_scope(project_name, features):
    if len(features) >= 2:
        core_plan = f"{features[0]}, {features[1]}"
        stretch_count = len(features) - 2
    elif len(features) == 1:
        core_plan = features[0]
        stretch_count = 0
    else:
        core_plan = "No core features yet"
        stretch_count = 0

    return {
        "name": project_name,
        "core_plan": core_plan,
        "stretch_count": stretch_count,
    }

